          "body": [
            {
              "_type": "block",
              "_key": "1da5391d2cb2",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "d22277b252d2",
                  "text": "Come join BMW CCA Puget Sound on Sept 24th for another great High Performance Driving Education(HPDE) at Pacific Raceway.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "af1f87eb0bcb",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "b3d529c0ca01",
                  "text": "Cost: $400 for the day, including lunch. Note: MSR has added an additional $2 fee per registration unless you are a Hagerty Drivers Club member.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "f1d643dde8cf",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "4a8260cbd7d4",
                  "text": "Registration will close 5 days prior to the event or when the event reaches capacity.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "c38bdd2a3319",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "528fb4e30d5a",
                  "text": "Confirmation: You be waitlisted initially and confirmed as soon as possible given run group capacity and instructor availability. You will be charged upon confirmation.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "0100f4f43e28",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "1f365c55ea73",
                  "text": "BMWCCA Puget Sound Region has provided High Performance Driving events at Pacific Raceway and other tracks for more than 40 years. We have a strong safety record and an experienced group of trained Instructors and staff.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "d46038147ee7",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "2c441cc18f04",
                  "text": "Our Values",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "9c25b88f0de5",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "608c3d8f6bab",
                  "text": "Safety - First and foremost.\nFun\nEducational – Emphasis on improving skills.\nWelcoming - Friendly and casual.\nApproachable\nInclusive - Open to all members with all skills and all types of cars.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "931ff447abcd",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "5942cf6f5814",
                  "text": "Attendees are assigned to one of three run groups by the Chief Driving Instructor, based on the skills and abilities of the driver, vehicle, and other participating drivers. Groups run from Novice, where all drivers are instructed to Advanced/Instructors where all drivers are Solo. Others may be instructed or solo depending on driver skill. Passing rules vary by run group. Drivers are expected to advance over time with improving skills and abilities.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "b971f0e84dd9",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "2cddbd28c437",
                  "text": "Following time on track, run groups will meet in educational breakout sessions for discussion about the track, conditions, traffic management, driving theory, and tips for improvement.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "fe718db38c20",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "49420758db5b",
                  "text": "See https://bmw-club-psr.org/driver-education for more information about the HPDE program.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "d427b78d055d",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "c6bfdc703b30",
                  "text": "Cancellation Policy:",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "2a7586d21415",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "2b2ca433fac5",
                  "text": "As a not-for-profit club, it is BMW CCA PSR's goal to provide exceptional events while breaking even financially. Event expenses (venue rental, corner workers, ambulance services, catering, etc.) are fixed and paid in advance. The cancellation policy for this event is as follows:",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "eaf971e02c0a",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "5ebfb3af33c9",
                  "text": "• Cancellations received prior to two weeks before the event will be 100% refunded.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "fa2514e27836",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "908cc4f1a4fe",
                  "text": "• No refunds or credits will be given if canceled after the time stated above or if you do not attend the event.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "310b9817721f",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "84fceded0f11",
                  "text": "• It is the attendee’s responsibility to prepare and bring a vehicle that is safe for the event and meets the club’s safety and technical requirements. There will be no refunds for mechanical failure.",
                  "marks": []
                }
              ]
            },
            {
              "_type": "block",
              "_key": "a04cf3f261cd",
              "style": "normal",
              "markDefs": [],
              "children": [
                {
                  "_type": "span",
                  "_key": "b24b43e1f79e",
                  "text": "• No refunds will be issued due to halting an event for any reason - rain, incident, etc.",
                  "marks": []
                }
              ]
            }
          ],
          "sourceImageUrl": "https://dl.motorsportreg.com/28022b62-fef2-4b2a-9e8f-f1d486ee917d/-/crop/2841x1596/0,0/-/preview/-/progressive/yes/-/scale_crop/1012x606/center/-/format/png/msr.png",
